import React, { Component } from "react";
import { Fade, Slide } from "react-reveal";

const WEB3FORMS_ACCESS_KEY = "3958fb2b-b068-4c2e-8942-c46a606155c3";

class Contact extends Component {
  constructor(props) {
    super(props);
    this.state = {
      name: "",
      email: "",
      subject: "",
      message: "",
      sending: false,
      sent: false,
      error: false,
    };
    this.handleChange = this.handleChange.bind(this);
    this.handleSubmit = this.handleSubmit.bind(this);
  }

  handleChange(e) {
    this.setState({ [e.target.name]: e.target.value });
  }

  async handleSubmit(e) {
    e.preventDefault();
    const { name, email, subject, message } = this.state;

    if (!name || !email || !message) {
      this.setState({ error: "Please fill in Name, Email, and Message." });
      return;
    }

    this.setState({ sending: true, error: false });

    try {
      const res = await fetch("https://api.web3forms.com/submit", {
        method: "POST",
        headers: { "Content-Type": "application/json", Accept: "application/json" },
        body: JSON.stringify({
          access_key: WEB3FORMS_ACCESS_KEY,
          name,
          email,
          subject: subject || "Portfolio Contact",
          message,
        }),
      });

      if (res.ok) {
        this.setState({ sent: true, sending: false, name: "", email: "", subject: "", message: "" });
      } else {
        const data = await res.json();
        this.setState({ error: data.error || "Something went wrong. Please try again.", sending: false });
      }
    } catch (err) {
      this.setState({ error: "Network error. Please try again.", sending: false });
    }
  }

  render() {
    if (!this.props.data) return null;

    const { name, email, subject, message, sending, sent, error } = this.state;
    const contactMessage = this.props.data.contactmessage;
    const phone = this.props.data.phone;

    return (
      <section id="contact">
        <Fade bottom duration={1000}>
          <div className="row section-head">
            <div className="two columns header-col">
              <h1>
                <span>Get In Touch.</span>
              </h1>
            </div>
            <div className="ten columns">
              <p className="lead">{contactMessage}</p>
            </div>
          </div>
        </Fade>

        <div className="row">
          <Slide left duration={1000}>
            <div className="eight columns">
              {sent ? (
                <div id="message-success" style={{ display: "block" }}>
                  <i className="fa fa-check"></i> Your message was sent -- I'll get back to you soon!
                </div>
              ) : (
                <form onSubmit={this.handleSubmit} id="contactForm" name="contactForm">
                  <fieldset>
                    <div>
                      <label htmlFor="contactName">Name <span className="required">*</span></label>
                      <input
                        type="text"
                        size="35"
                        id="contactName"
                        name="name"
                        value={name}
                        onChange={this.handleChange}
                      />
                    </div>
                    <div>
                      <label htmlFor="contactEmail">Email <span className="required">*</span></label>
                      <input
                        type="email"
                        size="35"
                        id="contactEmail"
                        name="email"
                        value={email}
                        onChange={this.handleChange}
                      />
                    </div>
                    <div>
                      <label htmlFor="contactSubject">Subject</label>
                      <input
                        type="text"
                        size="35"
                        id="contactSubject"
                        name="subject"
                        value={subject}
                        onChange={this.handleChange}
                      />
                    </div>
                    <div>
                      <label htmlFor="contactMessage">Message <span className="required">*</span></label>
                      <textarea
                        cols="50"
                        rows="15"
                        id="contactMessage"
                        name="message"
                        value={message}
                        onChange={this.handleChange}
                      />
                    </div>
                    <div>
                      <button className="contact-submit" type="submit" disabled={sending}>
                        {sending ? "Sending..." : "Submit"}
                      </button>
                    </div>
                    {error && (
                      <div id="message-warning" style={{ display: "block" }}>
                        {error}
                      </div>
                    )}
                  </fieldset>
                </form>
              )}
            </div>
          </Slide>

          <Slide right duration={1000}>
            <aside className="four columns footer-widgets">
              <div className="widget widget_contact">
                <h4>Contact</h4>
                <p className="address">
                  <span>{phone}</span>
                  <br />
                  <a href="mailto:erictang0220@gmail.com" style={{ color: "#11ABB0" }}>
                    erictang0220@gmail.com
                  </a>
                </p>
              </div>
            </aside>
          </Slide>
        </div>
      </section>
    );
  }
}

export default Contact;
