import React from "react";
import Card from "./Card"
import Carousel from "react-multi-carousel";
import Slide from "react-reveal";
import "react-multi-carousel/lib/styles.css";
import {isMobile} from 'react-device-detect';

const response = {
  desktop: {
    breakpoint: { max: 3000, min: 1024 },
    items: 1,
    slidesToSlide: 1
  },
  tablet: {
    breakpoint: { max: 1024, min: 464 },
    items: 1,
    slidesToSlide: 1
  },
  mobile: {
    breakpoint: { max: 464, min: 0 },
    items: 1,
    slidesToSlide: 1
  }
};

export default function FullCarousel(props) {
    var tmp;
    if (props.data === undefined) tmp = [];
    else tmp = props.data.pieces;
    const allArt = tmp.map((piece) => {
        return (
            <Card key={piece.name} info={piece}/>
        );
    });

    return (
        <section id="gallery">
          <Slide left duration={2000}>
                <h4
                    style={{
                        textAlign: "center",
                        font: "30px/24px opensans-bold, sans-serif",
                        paddingTop: "100px",
                        paddingBottom: "40px",
                        color: "#a1a1a1",
                        letterSpacing: "2.5px",
                        
                      }}
                > ART GALLERY
                </h4>
                
                <Carousel
                    swipeable={true}
                    draggable={true}
                    showDots={false}
                    arrows={true}
                    centerMode={true}
                    responsive={response}
                    ssr={true}
                    infinite={true}
                    autoPlay={false}
                    keyBoardControl={true}
                    transitionDuration={700}
                    customTransition="transform 700ms ease-in-out"
                    containerClass="carousel-container-with-arrow"
                    renderButtonGroupOutside={true}
                    renderDotsOutside={true}
                    dotListClass="custom-dot-list-style"
                    itemClass="carousel-item-padding"
                    className="fixed"
                    >
                    
                    {allArt}
                    
                </Carousel>
              </Slide>
          
        </section>
    );
}