import React, { Component } from "react";
import Fade from "react-reveal";
import Zmage from "react-zmage";

class ArtworkGallery extends Component {
  render() {
    if (!this.props.data) return null;

    const pieces = this.props.data.pieces.map(function (piece, i) {
      const imgSrc = process.env.PUBLIC_URL + "/images/artImages/" + piece.image;
      return (
        <div key={i} className="artwork-card">
          <Zmage src={imgSrc} className="artwork-thumb" alt={piece.name} />
          <div className="artwork-info">
            <h5 className="artwork-name">{piece.name}</h5>
            <p className="artwork-medium">{piece.date}</p>
            {piece.story && <p className="artwork-story">{piece.story}</p>}
          </div>
        </div>
      );
    });

    return (
      <section id="artwork-gallery">
        <Fade bottom duration={1000} distance="40px">
          <div className="artwork-gallery-container">
            <h2 className="artwork-gallery-title">All Works</h2>
            <div className="artwork-grid">{pieces}</div>
          </div>
        </Fade>
      </section>
    );
  }
}

export default ArtworkGallery;
